ps.pstext:
if !IsFeatureImplemented(FEAT_PAuth_LR) then EndOfDecode(Decode_UNDEF); end;

let use_key_a : boolean = opc[0] == '0';
let offset : bits(64) = ZeroExtend{}(imm16::'00');
let auth_then_branch : boolean = TRUE;

var inst_type : GCSInstruction;
var target : bits(64) = X{}(30);

let modifier : bits(64) = SP{}();
let modifier2 : bits(64) = PC64() - offset;

if use_key_a then
    target = AuthIA2(target, modifier, modifier2, auth_then_branch);
else
    target = AuthIB2(target, modifier, modifier2, auth_then_branch);
end;

if IsFeatureImplemented(FEAT_GCS) && GCSPCREnabled(PSTATE.EL) then
    inst_type = if use_key_a then GCSInstType_PRETAA else GCSInstType_PRETAB;
    target = LoadCheckGCSRecord(target, inst_type);
    SetCurrentGCSPointer(GetCurrentGCSPointer() + 8);
end;

// Value in BTypeNext will be used to set PSTATE.BTYPE
BTypeNext = '00';

let branch_conditional : boolean = FALSE;
BranchTo{64}(target, BranchType_RET, branch_conditional);
